package workloadmanager

import (
	"context"
	"fmt"

	corev1 "k8s.io/api/core/v1"
	k8serrors "k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/apimachinery/pkg/labels"
	"k8s.io/client-go/informers/core/v1"
	sandboxv1alpha1 "sigs.k8s.io/agent-sandbox/api/v1alpha1"
)

const sandboxNameLabel = "runtime.agentcube.io/sandbox-name"

type PodIPResolver struct {
	podInformer v1.PodInformer
}

func NewPodIPResolver(podInformer v1.PodInformer) *PodIPResolver {
	return &PodIPResolver{
		podInformer: podInformer,
	}
}

func (r *PodIPResolver) ResolvePodIP(ctx context.Context, sandboxName, sandboxNamespace string, sandboxAnnotations map[string]string) (string, error) {
	podName := sandboxName

	if annotatedPodName, exists := sandboxAnnotations["agents.x-k8s.io/sandbox-pod-name"]; exists && annotatedPodName != "" {
		podName = annotatedPodName
	}

	pod, err := r.podInformer.Lister().Pods(sandboxNamespace).Get(podName)
	if err == nil {
		if pod.Status.Phase != corev1.PodRunning {
			return "", fmt.Errorf("pod %s is not running (phase: %s)", podName, pod.Status.Phase)
		}
		if pod.Status.PodIP == "" {
			return "", fmt.Errorf("pod %s has no IP assigned", podName)
		}
		return pod.Status.PodIP, nil
	}

	if !k8serrors.IsNotFound(err) {
		return "", err
	}

	selector, err := labels.Parse(fmt.Sprintf("%s=%s", sandboxNameLabel, sandboxName))
	if err != nil {
		return "", fmt.Errorf("failed to parse label selector: %w", err)
	}

	pods, err := r.podInformer.Lister().Pods(sandboxNamespace).List(selector)
	if err != nil {
		return "", fmt.Errorf("failed to list pods: %w", err)
	}

	if len(pods) == 0 {
		return "", fmt.Errorf("no pods found with label %s=%s", sandboxNameLabel, sandboxName)
	}

	for _, pod := range pods {
		if hasOwnerReference(pod, sandboxv1alpha1.SandboxKind, sandboxName) {
			if pod.Status.Phase == corev1.PodRunning && pod.Status.PodIP != "" {
				return pod.Status.PodIP, nil
			}
		}
	}

	return "", fmt.Errorf("no running pod with owner reference found for sandbox %s", sandboxName)
}

func hasOwnerReference(pod *corev1.Pod, kind, name string) bool {
	for _, ownerRef := range pod.OwnerReferences {
		if ownerRef.Kind == kind && ownerRef.Name == name {
			return true
		}
	}
	return false
}

package workloadmanager

import (
	"context"
	"fmt"
	"time"

	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/apis/meta/v1/unstructured"
	"k8s.io/apimachinery/pkg/watch"
	"k8s.io/client-go/dynamic"
)

type SandboxWatcher struct {
	namespace string
	name      string
	resource  dynamic.ResourceInterface
	timeout   time.Duration
	done      chan struct{}
}

type WatchResult struct {
	PodIP string
	Ready bool
	Error error
}

func NewSandboxWatcher(namespace, name string, resource dynamic.ResourceInterface, timeout time.Duration) *SandboxWatcher {
	return &SandboxWatcher{
		namespace: namespace,
		name:      name,
		resource:  resource,
		timeout:   timeout,
		done:      make(chan struct{}),
	}
}

func (r *SandboxWatcher) Watch(ctx context.Context) <-chan WatchResult {
	resultChan := make(chan WatchResult, 1)

	go func() {
		watchOpts := metav1.ListOptions{
			ResourceVersion: "0",
			Watch:           true,
		}

		watcher, err := r.resource.Watch(ctx, watchOpts)
		if err != nil {
			resultChan <- WatchResult{Error: err}
			close(resultChan)
			return
		}
		defer watcher.Stop()

		ctx, cancel := context.WithTimeout(ctx, r.timeout)
		defer cancel()

		for {
			select {
			case <-ctx.Done():
				resultChan <- WatchResult{Error: fmt.Errorf("sandbox creation timed out")}
				close(resultChan)
				return
			case <-r.done:
				close(resultChan)
				return
			case event, ok := <-watcher.ResultChan():
				if !ok {
					break
				}

				if event.Type == watch.Deleted {
					continue
				}

				obj, ok := event.Object.(*unstructured.Unstructured)
				if !ok {
					continue
				}

				status, found, err := unstructured.NestedMap(obj.Object, "status")
				if !found || err != nil {
					continue
				}

				phase, _, _ := unstructured.NestedString(status, "phase")
				if phase != "Running" {
					continue
				}

				podName, _, _ := unstructured.NestedString(status, "podName")
				if podName == "" {
					continue
				}

				podIP, _, _ := unstructured.NestedString(status, "podIP")

				resultChan <- WatchResult{
					PodIP: podIP,
					Ready: true,
				}
				close(resultChan)
				return
			}
		}
	}()

	return resultChan
}

func (r *SandboxWatcher) Stop() {
	close(r.done)
}

