package valkey

import (
	"os"
	"strconv"
	"strings"
)

type ValkeyConfig struct {
	Addr            string
	Password        string
	PasswordRequired bool
	DisableCache    bool
	ForceSingle     bool
}

func LoadValkeyConfigFromEnv() (*ValkeyConfig, error) {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		return nil, &ConfigError{Field: "VALKEY_ADDR", Message: "required"}
	}

	password := os.Getenv("VALKEY_PASSWORD")

	passwordRequiredStr := os.Getenv("VALKEY_PASSWORD_REQUIRED")
	passwordRequired := true
	if passwordRequiredStr != "" {
		var err error
		passwordRequired, err = strconv.ParseBool(passwordRequiredStr)
		if err != nil {
			passwordRequired = true
		}
	}

	if passwordRequired && password == "" {
		return nil, &ConfigError{Field: "VALKEY_PASSWORD", Message: "required when VALKEY_PASSWORD_REQUIRED is true"}
	}

	disableCacheStr := os.Getenv("VALKEY_DISABLE_CACHE")
	disableCache := false
	if disableCacheStr != "" {
		disableCache, _ = strconv.ParseBool(disableCacheStr)
	}

	forceSingleStr := os.Getenv("VALKEY_FORCE_SINGLE")
	forceSingle := false
	if forceSingleStr != "" {
		forceSingle, _ = strconv.ParseBool(forceSingleStr)
	}

	return &ValkeyConfig{
		Addr:            addr,
		Password:        password,
		PasswordRequired: passwordRequired,
		DisableCache:    disableCache,
		ForceSingle:     forceSingle,
	}, nil
}

type ConfigError struct {
	Field   string
	Message string
}

func (e *ConfigError) Error() string {
	return "valkey config error: " + e.Field + " is " + e.Message
}

func (c *ValkeyConfig) GetAddresses() []string {
	return strings.Split(c.Addr, ",")
}

