	secretName string
}

func NewJWTManager(k8sClient kubernetes.Interface, namespace string) (*JWTManager, error) {
	if namespace == "" {
		namespace = os.Getenv("AGENTCUBE_NAMESPACE")
		if namespace == "" {
			namespace = "default"
		}
	}

	jm := &JWTManager{
		clientset:  k8sClient,
		namespace:  namespace,
		secretName: IdentitySecretName,
	}

	ctx := context.Background()
	if err := jm.TryStoreOrLoadJWTKeySecret(ctx); err != nil {
		return nil, fmt.Errorf("failed to initialize JWT keys: %w", err)
	}

	return jm, nil
}

func (jm *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context) error {
	secret, err := jm.clientset.CoreV1().Secrets(jm.namespace).Get(ctx, jm.secretName, metav1.GetOptions{})
	if err != nil {
		if k8serrors.IsNotFound(err) {
			return jm.generateAndStoreKey(ctx)
		}
		return err
	}

	return jm.loadExistingKey(secret)
}

func (jm *JWTManager) generateAndStoreKey(ctx context.Context) error {
	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		return fmt.Errorf("failed to generate RSA key: %w", err)
	}

	jm.privateKey = privateKey
	jm.publicKey = &privateKey.PublicKey

	publicKeyBytes, err := x509.MarshalPKIXPublicKey(jm.publicKey)
	if err != nil {
		return fmt.Errorf("failed to marshal public key: %w", err)
	}

	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      jm.secretName,
			Namespace: jm.namespace,
		},
		Type: corev1.SecretTypeOpaque,
		Data: map[string][]byte{
			PrivateKeyDataKey: pem.EncodeToMemory(&pem.Block{
				Type:  "RSA PRIVATE KEY",
				Bytes: x509.MarshalPKCS1PrivateKey(jm.privateKey),
			}),
			PublicKeyDataKey: publicKeyBytes,
		},
	}

	_, err = jm.clientset.CoreV1().Secrets(jm.namespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		if k8serrors.IsAlreadyExists(err) {
			return jm.TryStoreOrLoadJWTKeySecret(ctx)
		}
		return fmt.Errorf("failed to create secret: %w", err)
	}

	return nil
}

func (jm *JWTManager) loadExistingKey(secret *corev1.Secret) error {
	privateBlock, _ := pem.Decode(secret.Data[PrivateKeyDataKey])
	if privateBlock == nil {
		return fmt.Errorf("failed to decode private key PEM")
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(privateBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	publicBlock, _ := pem.Decode(secret.Data[PublicKeyDataKey])
	if publicBlock == nil {
		return fmt.Errorf("failed to decode public key PEM")
	}

	publicKey, err := x509.ParsePKIXPublicKey(publicBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	rsaPublicKey, ok := publicKey.(*rsa.PublicKey)
	if !ok {
		return fmt.Errorf("public key is not RSA")
	}

	jm.privateKey = privateKey
	jm.publicKey = rsaPublicKey

	return nil
}

func (jm *JWTManager) GenerateToken(sessionID, sandboxID string, expiration time.Duration) (string, error) {
	claims := jwt.MapClaims{
		"session_id":  sessionID,
		"sandbox_id":  sandboxID,
		"exp":         time.Now().Add(expiration).Unix(),
		"iat":         time.Now().Unix(),
		"iss":         "agentcube-router",
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	return token.SignedString(jm.privateKey)
}

func (jm *JWTManager) PublicKey() *rsa.PublicKey {
	return jm.publicKey
}

func (jm *JWTManager) PrivateKey() *rsa.PrivateKey {
	return jm.privateKey
}

package router

import (
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

const (
	MaxBodySize = 32 << 20
)

type AuthManager struct {
	publicKey *rsa.PublicKey
	leeway    time.Duration
}

func NewAuthManager(publicKey *rsa.PublicKey) *AuthManager {
	return &AuthManager{
		publicKey: publicKey,
		leeway:    1 * time.Minute,
	}
}

func (m *AuthManager) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
			c.Abort()
			return
		}

		tokenString := authHeader
		if len(authHeader) > 7 && authHeader[:7] == "Bearer " {
			tokenString = authHeader[7:]
		}

		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}
			return m.publicKey, nil
		},
			jwt.WithExpirationRequired(),
			jwt.WithIssuedAt(),
			jwt.WithLeeway(m.leeway),
		)

		if err != nil || !token.Valid {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid or expired token"})
			c.Abort()
			return
		}

		c.Request.Body = http.MaxBytesReader(c.ResponseWriter, c.Request.Body, MaxBodySize)
		c.Next()
	}
}

