package picod

import (
	"os"
	"testing"

	"github.com/stretchr/testify/assert"
)

func TestParseFileModeEmpty(t *testing.T) {
	mode, err := parseFileMode("")
	assert.NoError(t, err)
	assert.Equal(t, os.FileMode(0644), mode)
}

func TestParseFileModeValid(t *testing.T) {
	mode, err := parseFileMode("0755")
	assert.NoError(t, err)
	assert.Equal(t, os.FileMode(0755), mode)
}

func TestParseFileModeInvalid(t *testing.T) {
	mode, err := parseFileMode("abc")
	assert.Error(t, err)
	assert.Equal(t, os.FileMode(0644), mode)
}

func TestParseFileModeExceedsMax(t *testing.T) {
	mode, err := parseFileMode("01000")
	assert.Error(t, err)
	assert.Equal(t, os.FileMode(0644), mode)
}

func TestValidateFileMode(t *testing.T) {
	assert.True(t, validateFileMode(0644))
	assert.True(t, validateFileMode(0755))
	assert.True(t, validateFileMode(0777))
	assert.False(t, validateFileMode(01000))
}

package workloadmanager

import (
	"context"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/apis/meta/v1/unstructured"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/watch"
	"k8s.io/client-go/dynamic/fake"
)

func TestWatchSandboxCreationSuccess(t *testing.T) {
	obj := &unstructured.Unstructured{
		Object: map[string]interface{}{
			"apiVersion": "v1alpha1",
			"kind":       "Sandbox",
			"metadata": map[string]interface{}{
				"name":      "test-sandbox",
				"namespace": "default",
			},
			"status": map[string]interface{}{
				"phase":   "Running",
				"podName": "test-pod",
				"podIP":   "10.0.0.1",
			},
		},
	}

	scheme := runtime.NewScheme()
	client := fake.NewSimpleDynamicClient(scheme, obj)
	resource := client.Resource(metav1.GroupVersionResource{
		Group:    "v1alpha1",
		Resource: "sandboxes",
	}).Namespace("default")

	watcher := NewSandboxWatcher("default", "test-sandbox", resource, 2*time.Minute)

	ctx := context.Background()
	resultChan := watcher.Watch(ctx)

	select {
	case result := <-resultChan:
		assert.True(t, result.Ready)
		assert.Equal(t, "10.0.0.1", result.PodIP)
		assert.NoError(t, result.Error)
	case <-time.After(5 * time.Second):
		t.Fatal("watcher timed out")
	}
}

func TestWatchSandboxTimeout(t *testing.T) {
	scheme := runtime.NewScheme()
	client := fake.NewSimpleDynamicClient(scheme)
	resource := client.Resource(metav1.GroupVersionResource{
		Group:    "v1alpha1",
		Resource: "sandboxes",
	}).Namespace("default")

	watcher := NewSandboxWatcher("default", "test-sandbox", resource, 100*time.Millisecond)

	ctx := context.Background()
	resultChan := watcher.Watch(ctx)

	select {
	case result := <-resultChan:
		assert.False(t, result.Ready)
		assert.Error(t, result.Error)
		assert.Contains(t, result.Error.Error(), "timed out")
	case <-time.After(5 * time.Second):
		t.Fatal("test timed out")
	}
}

func TestWatchSandboxDeleted(t *testing.T) {
	scheme := runtime.NewScheme()
	client := fake.NewSimpleDynamicClient(scheme)
	resource := client.Resource(metav1.GroupVersionResource{
		Group:    "v1alpha1",
		Resource: "sandboxes",
	}).Namespace("default")

	watcher := NewSandboxWatcher("default", "test-sandbox", resource, 1*time.Second)

	ctx, cancel := context.WithTimeout(context.Background(), 500*time.Millisecond)
	defer cancel()

	resultChan := watcher.Watch(ctx)

	fakeWatcher := watch.NewFake()
	go func() {
		fakeWatcher.Modify(&unstructured.Unstructured{
			Object: map[string]interface{}{
				"metadata": map[string]interface{}{
					"name":      "test-sandbox",
					"namespace": "default",
				},
			},
		})
	}()

	select {
	case result := <-resultChan:
		assert.Error(t, result.Error)
	case <-ctx.Done():
	}
}

package picod

import (
	"fmt"
	"os"
	"strconv"
)

const (
	DefaultFileMode os.FileMode = 0644
	MaxFileMode     os.FileMode = 0777
)

func parseFileMode(modeStr string) (os.FileMode, error) {
	if modeStr == "" {
		return DefaultFileMode, nil
	}

	mode, err := strconv.ParseUint(modeStr, 8, 32)
	if err != nil {
		return DefaultFileMode, fmt.Errorf("invalid mode format: %w", err)
	}

	if mode > uint64(MaxFileMode) {
		return DefaultFileMode, fmt.Errorf("mode exceeds maximum 0777")
	}

	return os.FileMode(mode), nil
}

func validateFileMode(mode os.FileMode) bool {
	return mode <= MaxFileMode
}

