input.content:
package services

import (
	"archive/tar"
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"time"

	"github.com/docker/docker/api/types"
	"github.com/docker/docker/api/types/filters"
	"github.com/docker/docker/client"
)

type DockerService struct {
	cli *client.Client
}

func NewDockerService() (*DockerService, error) {
	ctx := context.Background()
	cli, err := client.NewClientWithOpts(client.FromEnv, client.WithAPIVersionNegotiation())
	if err != nil {
		return nil, fmt.Errorf("failed to create Docker client: %w", err)
	}

	_, err = cli.Ping(ctx)
	if err != nil {
		return nil, fmt.Errorf("Docker is not available or not running: %w", err)
	}

	return &DockerService{cli: cli}, nil
}

func (s *DockerService) CheckDockerAvailable() error {
	ctx := context.Background()
	_, err := s.cli.Info(ctx)
	return err
}

type BuildResult struct {
	ImageName   string `json:"image_name"`
	ImageID     string `json:"image_id"`
	ImageSize   int64  `json:"image_size"`
	BuildTimeMs int64  `json:"build_time"`
}

func (s *DockerService) BuildImage(workspacePath, imageName, tag string, buildArgs map[string]string) (*BuildResult, error) {
	ctx := context.Background()
	startTime := time.Now()

	tarReader, err := s.createTar(workspacePath)
	if err != nil {
		return nil, fmt.Errorf("failed to create tar: %w", err)
	}
	defer tarReader.Close()

	buildArgsMap := make(map[string]*string)
	for k, v := range buildArgs {
		value := v
		buildArgsMap[k] = &value
	}

	opts := types.ImageBuildOptions{
		Tags:        []string{fmt.Sprintf("%s:%s", imageName, tag)},
		BuildArgs:   buildArgsMap,
		Remove:      true,
		ForceRemove: true,
		PullParent:  false,
	}

	resp, err := s.cli.ImageBuild(ctx, tarReader, opts)
	if err != nil {
		return nil, fmt.Errorf("failed to build image: %w", err)
	}
	defer resp.Body.Close()

	s.streamLogs(resp.Body)

	inspect, _, err := s.cli.ImageInspectWithRaw(ctx, fmt.Sprintf("%s:%s", imageName, tag))
	if err != nil {
		return nil, fmt.Errorf("failed to inspect image: %w", err)
	}

	buildTime := time.Since(startTime).Milliseconds()

	return &BuildResult{
		ImageName:   fmt.Sprintf("%s:%s", imageName, tag),
		ImageID:     inspect.ID,
		ImageSize:   inspect.Size,
		BuildTimeMs: buildTime,
	}, nil
}

type PushResult struct {
	PushedImage string `json:"pushed_image"`
	PushTimeMs  int64  `json:"push_time"`
}

func (s *DockerService) PushImage(imageName, registryURL, username, password string) (*PushResult, error) {
	ctx := context.Background()
	startTime := time.Now()

	targetImage := imageName
	if registryURL != "" && registryURL != "" {
		targetImage = fmt.Sprintf("%s/%s", registryURL, imageName)
		err := s.cli.ImageTag(ctx, imageName, targetImage)
		if err != nil {
			return nil, fmt.Errorf("failed to tag image: %w", err)
		}
	}

	if username != "" && password != "" {
		authConfig := types.AuthConfig{
			Username: username,
			Password: password,
		}
		_, err := s.cli.RegistryLogin(ctx, authConfig)
		if err != nil {
			return nil, fmt.Errorf("failed to login to registry: %w", err)
		}
	}

	resp, err := s.cli.ImagePush(ctx, targetImage, types.ImagePushOptions{})
	if err != nil {
		return nil, fmt.Errorf("failed to push image: %w", err)
	}
	defer resp.Close()

	s.streamLogs(resp)

	pushTime := time.Since(startTime).Milliseconds()

	return &PushResult{
		PushedImage: targetImage,
		PushTimeMs:  pushTime,
	}, nil
}

func (s *DockerService) RemoveImage(imageName string) bool {
	ctx := context.Background()
	_, err := s.cli.ImageRemove(ctx, imageName, types.ImageRemoveOptions{Force: false})
	if err != nil {
		return false
	}
	return true
}

func (s *DockerService) createTar(workspacePath string) (io.ReadCloser, error) {
	pr, pw := io.Pipe()
	tw := tar.NewWriter(pw)

	go func() {
		defer pw.Close()
		defer tw.Close()

		err := filepath.Walk(workspacePath, func(path string, info os.FileInfo, err error) error {
			if err != nil {
				return err
			}

			if info.Name() == ".git" || info.Name() == "node_modules" || info.Name() == "__pycache__" {
				if info.IsDir() {
					return filepath.SkipDir
				}
				return nil
			}

			header, err := tar.FileInfoHeader(info, info.Name())
			if err != nil {
				return err
			}

			relPath, err := filepath.Rel(workspacePath, path)
			if err != nil {
				return err
			}
			header.Name = relPath

			if err := tw.WriteHeader(header); err != nil {
				return err
			}

			if !info.IsDir() {
				file, err := os.Open(path)
				if err != nil {
					return err
				}
				defer file.Close()

				_, err = io.Copy(tw, file)
				if err != nil {
					return err
				}
			}

			return nil
		})

		if err != nil {
			pw.CloseWithError(err)
		}
	}()

	return pr, nil
}

func (s *DockerService) streamLogs(reader io.Reader) {
	decoder := json.NewDecoder(reader)
	for {
		var msg map[string]interface{}
		if err := decoder.Decode(&msg); err != nil {
			if err == io.EOF {
				break
			}
			return
		}

		if stream, ok := msg["stream"].(string); ok {
			fmt.Print(stream)
		}
		if status, ok := msg["status"].(string); ok {
			fmt.Printf("%s", status)
			if id, ok := msg["id"].(string); ok {
				fmt.Printf(": %s", id)
			}
			fmt.Println()
		}
	}
}

func (s *DockerService) ListImages() ([]types.ImageSummary, error) {
	ctx := context.Background()
	images, err := s.cli.ImageList(ctx, types.ImageListOptions{
		Filters: filters.NewArgs(),
	})
	if err != nil {
		return nil, err
	}
	return images, nil
}

func (s *DockerService) ImageExists(imageName string) bool {
	ctx := context.Background()
	_, _, err := s.cli.ImageInspectWithRaw(ctx, imageName)
	return err == nil
}

package agentd

import (
	"context"
	"testing"
	"time"

	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"sigs.k8s.io/controller-runtime/pkg/client/fake"
)

func TestReconcileNoAnnotation(t *testing.T) {
	sandbox := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-sandbox",
			Namespace: "default",
		},
	}

	scheme := runtime.NewScheme()
	_ = corev1.AddToScheme(scheme)

	client := fake.NewClientBuilder().WithScheme(scheme).WithObjects(sandbox).Build()
	reconciler := &Reconciler{Client: client, Scheme: scheme}

	ctx := context.Background()
	req := metav1.ObjectMeta{Name: "test-sandbox", Namespace: "default"}
	result, err := reconciler.Reconcile(ctx, req)

	if err != nil {
		t.Errorf("Expected no error, got %v", err)
	}
	if result.Requeue {
		t.Errorf("Expected no requeue, got %v", result.Requeue)
	}
}

func TestReconcileIdleTimeoutExceeded(t *testing.T) {
	lastActivity := time.Now().Add(-20 * time.Minute)

	sandbox := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-sandbox",
			Namespace: "default",
			Annotations: map[string]string{
				LastActivityAnnotationKey: lastActivity.Format(time.RFC3339),
			},
		},
	}

	scheme := runtime.NewScheme()
	_ = corev1.AddToScheme(scheme)

	client := fake.NewClientBuilder().WithScheme(scheme).WithObjects(sandbox).Build()
	reconciler := &Reconciler{Client: client, Scheme: scheme}

	ctx := context.Background()
	req := metav1.ObjectMeta{Name: "test-sandbox", Namespace: "default"}
	_, err := reconciler.Reconcile(ctx, req)

	if err != nil {
		t.Errorf("Expected no error, got %v", err)
	}
}

func TestReconcileNotYetExpired(t *testing.T) {
	lastActivity := time.Now().Add(-5 * time.Minute)

	sandbox := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-sandbox",
			Namespace: "default",
			Annotations: map[string]string{
				LastActivityAnnotationKey: lastActivity.Format(time.RFC3339),
			},
		},
	}

	scheme := runtime.NewScheme()
	_ = corev1.AddToScheme(scheme)

	client := fake.NewClientBuilder().WithScheme(scheme).WithObjects(sandbox).Build()
	reconciler := &Reconciler{Client: client, Scheme: scheme}

	ctx := context.Background()
	req := metav1.ObjectMeta{Name: "test-sandbox", Namespace: "default"}
	result, err := reconciler.Reconcile(ctx, req)

	if err != nil {
		t.Errorf("Expected no error, got %v", err)
	}
	if result.RequeueAfter <= 0 {
		t.Errorf("Expected requeue after, got %v", result.RequeueAfter)
	}
}

{{/*
Expand the name of the chart.
*/}}
{{- define "agentcube.name" -}}
{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Create a default fully qualified app name.
We truncate at 63 chars because some Kubernetes name fields are limited to this (by the DNS naming spec).
*/}}
{{- define "agentcube.fullname" -}}
{{- if .Values.fullnameOverride }}
{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- $name := default .Chart.Name .Values.nameOverride }}
{{- if contains $name .Release.Name }}
{{- .Release.Name | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- printf "%s-%s" .Release.Name $name | trunc 63 | trimSuffix "-" }}
{{- end }}
{{- end }}
{{- end }}

{{/*
Create chart name and version as used by the chart label.
*/}}
{{- define "agentcube.chart" -}}
{{- printf "%s-%s" .Chart.Name .Chart.Version | replace "+" "_" | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Common labels
*/}}
{{- define "agentcube.labels" -}}
helm.sh/chart: {{ include "agentcube.chart" . }}
{{ include "agentcube.selectorLabels" . }}
{{- if .Chart.AppVersion }}
app.kubernetes.io/version: {{ .Chart.AppVersion | quote }}
{{- end }}
app.kubernetes.io/managed-by: {{ .Release.Service }}
{{- end }}

{{/*
Selector labels
*/}}
{{- define "agentcube.selectorLabels" -}}
app.kubernetes.io/name: {{ include "agentcube.name" . }}
app.kubernetes.io/instance: {{ .Release.Name }}
{{- end }}

{{/*
Create the name of the service account to use
*/}}
{{- define "agentcube.serviceAccountName" -}}
{{- if .Values.serviceAccount }}
{{- if .Values.serviceAccount.create }}
{{- default (include "agentcube.fullname" .) .Values.serviceAccount.name }}
{{- else }}
{{- default "default" .Values.serviceAccount.name }}
{{- end }}
{{- else }}
{{- include "agentcube.fullname" . }}
{{- end }}
{{- end }}

{{/*
Redis environment variables
*/}}
{{- define "agentcube.redisEnv" -}}
- name: REDIS_ADDR
  value: {{ .Values.redis.addr | quote }}
- name: REDIS_PASSWORD
  valueFrom:
    secretKeyRef:
      name: {{ include "agentcube.fullname" . }}-redis
      key: password
      optional: true
{{- end }}

{{/*
Workload Manager URL
*/}}
{{- define "agentcube.workloadManagerURL" -}}
{{- printf "http://%s-workloadmanager.%s.svc.cluster.local:%d" (include "agentcube.fullname" .) .Release.Namespace .Values.workloadmanager.service.port }}
{{- end }}

{{/*
Common environment variables for workloadmanager
*/}}
{{- define "agentcube.workloadmanagerEnv" -}}
- name: AGENTCUBE_NAMESPACE
  valueFrom:
    fieldRef:
      fieldPath: metadata.namespace
- name: WORKLOAD_MANAGER_URL
  value: {{ include "agentcube.workloadManagerURL" . | quote }}
{{- if .Values.redis.addr }}
{{- include "agentcube.redisEnv" . }}
{{- end }}
{{- if .Values.workloadmanager.extraEnv }}
{{- toYaml .Values.workloadmanager.extraEnv | nindent 0 }}
{{- end }}
{{- end }}

{{/*
Common environment variables for router
*/}}
{{- define "agentcube.routerEnv" -}}
- name: AGENTCUBE_NAMESPACE
  valueFrom:
    fieldRef:
      fieldPath: metadata.namespace
- name: WORKLOAD_MANAGER_URL
  value: {{ include "agentcube.workloadManagerURL" . | quote }}
{{- if .Values.redis.addr }}
{{- include "agentcube.redisEnv" . }}
{{- end }}
{{- if .Values.router.extraEnv }}
{{- toYaml .Values.router.extraEnv | nindent 0 }}
{{- end }}
{{- end }}

{{/*
Resource requests and limits
*/}}
{{- define "agentcube.resources" -}}
{{- $component := .component | default "workloadmanager" -}}
{{- $values := index $.Values $component -}}
{{- if $values.resources }}
resources:
  {{- if $values.resources.requests }}
  requests:
    {{- if $values.resources.requests.cpu }}
    cpu: {{ $values.resources.requests.cpu | quote }}
    {{- end }}
    {{- if $values.resources.requests.memory }}
    memory: {{ $values.resources.requests.memory | quote }}
    {{- end }}
  {{- end }}
  {{- if $values.resources.limits }}
  limits:
    {{- if $values.resources.limits.cpu }}
    cpu: {{ $values.resources.limits.cpu | quote }}
    {{- end }}
    {{- if $values.resources.limits.memory }}
    memory: {{ $values.resources.limits.memory | quote }}
    {{- end }}
  {{- end }}
{{- else }}
resources: {}
{{- end }}
{{- end }}

